# EVOLVE-BLOCK-START
#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>
#include <chrono>
#include <random>
#include <cmath>
#include <utility>

auto GLOBAL_START_TIME = std::chrono::steady_clock::now();
const double TIME_LIMIT_SECONDS = 1.90;

struct State {
    std::vector<std::vector<int>> stacks; // stacks[i] = boxes from bottom to top (0-indexed labels)
    std::vector<std::pair<int, int>> box_pos; // box_pos[v] = {stack_idx, height_idx}
    int N, M;
    long long energy;
    std::vector<std::pair<int, int>> ops; // {box_label+1, dest_stack+1 or 0}

    State() : N(0), M(0), energy(0) {}

    State(int n, int m, const std::vector<std::vector<int>>& init_stacks)
        : N(n), M(m), energy(0) {
        stacks.resize(M);
        box_pos.resize(N);
        for (int i = 0; i < M; i++) {
            stacks[i] = init_stacks[i];
            for (int j = 0; j < (int)stacks[i].size(); j++) {
                box_pos[stacks[i][j]] = {i, j};
            }
        }
    }

    void move(int box_val, int dest_stack) {
        int src = box_pos[box_val].first;
        int h = box_pos[box_val].second;
        int num_moved = (int)stacks[src].size() - h;

        for (int i = h; i < (int)stacks[src].size(); i++) {
            int bv = stacks[src][i];
            box_pos[bv] = {dest_stack, (int)stacks[dest_stack].size() + (i - h)};
        }

        stacks[dest_stack].insert(stacks[dest_stack].end(),
            stacks[src].begin() + h, stacks[src].end());
        stacks[src].erase(stacks[src].begin() + h, stacks[src].end());

        energy += num_moved + 1;
        ops.push_back({box_val + 1, dest_stack + 1});
    }

    void carry_out(int box_val) {
        int src = box_pos[box_val].first;
        stacks[src].pop_back();
        ops.push_back({box_val + 1, 0});
    }

    int stack_top(int si) const {
        if (stacks[si].empty()) return -1;
        return stacks[si].back();
    }
};

// Find the best destination for a group whose bottom element has label group_bottom
// Using patience-sort rule: find stack with smallest top > group_bottom
// Exclude src_stack and optionally target's stack
int find_best_dest_patience(const State& st, int group_bottom, int src_stack, int target_box) {
    int best_dest = -1;
    int best_top = std::numeric_limits<int>::max();

    // Phase 1: find stack with smallest top that is > group_bottom (patience sort)
    for (int i = 0; i < st.M; i++) {
        if (i == src_stack) continue;
        if (st.stacks[i].empty()) continue;
        int top = st.stack_top(i);
        if (top > group_bottom && top < best_top) {
            best_top = top;
            best_dest = i;
        }
    }

    if (best_dest != -1) return best_dest;

    // Phase 2: no valid patience-sort destination. Use an empty stack if available.
    for (int i = 0; i < st.M; i++) {
        if (i == src_stack) continue;
        if (st.stacks[i].empty()) return i;
    }

    // Phase 3: no empty stack either. Pick stack with largest top (least damage).
    int largest_top = -1;
    for (int i = 0; i < st.M; i++) {
        if (i == src_stack) continue;
        int top = st.stack_top(i);
        if (top > largest_top) {
            largest_top = top;
            best_dest = i;
        }
    }

    return best_dest;
}

// Find best destination considering the entire group and the target
int find_best_dest_advanced(const State& st, int group_bottom, int group_size,
                            int src_stack, int current_target) {
    int best_dest = -1;
    double best_score = std::numeric_limits<double>::max();

    for (int i = 0; i < st.M; i++) {
        if (i == src_stack) continue;
        double score = 0.0;

        if (st.stacks[i].empty()) {
            // Empty stack: neutral, slight penalty to preserve empty stacks
            score = 500.0 - (double)group_bottom * 0.01;
        } else {
            int top = st.stack_top(i);
            if (top > group_bottom) {
                // Good: maintains patience-sort order
                score = (double)top; // Prefer smallest top > group_bottom
            } else {
                // Bad: violates order, penalize heavily
                score = 10000.0 + (double)st.stacks[i].size() * 10.0;
                // Extra penalty if top is close to current_target (will be needed soon)
                if (top < current_target + 20) {
                    score += (20 - (top - current_target)) * 50.0;
                }
            }
        }
        // Slight preference for shorter stacks to spread load
        score += (double)st.stacks[i].size() * 0.1;

        if (score < best_score) {
            best_score = score;
            best_dest = i;
        }
    }

    return best_dest;
}

long long solve_multi_move(const std::vector<std::vector<int>>& init_stacks, int N, int M,
                           std::vector<std::pair<int, int>>& out_ops, bool use_advanced = true) {
    State st(N, M, init_stacks);

    for (int k = 0; k < N; k++) {
        // While box k is not on top of its stack
        while (true) {
            int src = st.box_pos[k].first;
            int h = st.box_pos[k].second;
            if (h == (int)st.stacks[src].size() - 1) break; // k is on top

            // Find maximal decreasing suffix from the top
            // Decreasing from bottom to top means: reading the suffix from bottom element to top,
            // labels are strictly decreasing
            auto& stk = st.stacks[src];
            int top_idx = (int)stk.size() - 1;

            // Find longest suffix from top that is decreasing (bottom to top)
            // i.e., stk[j] > stk[j+1] > ... > stk[top_idx]
            int group_start = top_idx;
            while (group_start > h + 1 && stk[group_start - 1] > stk[group_start]) {
                group_start--;
            }
            // Ensure group_start > h (don't include target box k)
            if (group_start <= h) group_start = h + 1;

            int group_bottom_val = stk[group_start]; // largest label in the group (bottom of group)
            int group_size = top_idx - group_start + 1;

            // Find best destination
            int dest;
            if (use_advanced) {
                dest = find_best_dest_advanced(st, group_bottom_val, group_size, src, k);
            } else {
                dest = find_best_dest_patience(st, group_bottom_val, src, k);
            }

            if (dest == -1) {
                // Fallback: just pick any other stack
                dest = (src + 1) % M;
            }

            st.move(stk[group_start], dest);
        }
        st.carry_out(k);
    }

    out_ops = std::move(st.ops);
    return st.energy;
}

// Variant: move all boxes above target to a single destination (original approach for comparison)
long long solve_single_move(const std::vector<std::vector<int>>& init_stacks, int N, int M,
                            std::vector<std::pair<int, int>>& out_ops,
                            const std::vector<int>& dest_choices) {
    State st(N, M, init_stacks);

    for (int k = 0; k < N; k++) {
        int src = st.box_pos[k].first;
        int h = st.box_pos[k].second;
        if (h < (int)st.stacks[src].size() - 1) {
            int first_above = st.stacks[src][h + 1];
            int dest = dest_choices[k];
            if (dest == src) dest = (src + 1) % M;
            st.move(first_above, dest);
        }
        st.carry_out(k);
    }

    out_ops = std::move(st.ops);
    return st.energy;
}

// SA to optimize single-move destination choices
void optimize_single_move_sa(const std::vector<std::vector<int>>& init_stacks, int N, int M,
                             std::vector<int>& best_dest_choices, long long& best_energy,
                             double time_budget) {
    std::mt19937 rng(42);
    auto start = std::chrono::steady_clock::now();

    std::vector<int> current = best_dest_choices;
    long long current_energy = best_energy;

    double T_init = 50.0;
    double T_final = 0.01;

    int iterations = 0;
    while (true) {
        double elapsed = std::chrono::duration<double>(std::chrono::steady_clock::now() - GLOBAL_START_TIME).count();
        if (elapsed >= TIME_LIMIT_SECONDS) break;

        double progress = std::min(1.0, (elapsed - (TIME_LIMIT_SECONDS - time_budget)) / time_budget);
        if (progress < 0) progress = 0;
        double T = T_init * std::pow(T_final / T_init, progress);

        std::vector<int> next = current;
        // Mutate: change 1-3 random positions
        int num_changes = 1 + (rng() % 3);
        for (int c = 0; c < num_changes; c++) {
            int idx = rng() % N;
            next[idx] = rng() % M;
        }

        std::vector<std::pair<int, int>> dummy_ops;
        long long next_energy = solve_single_move(init_stacks, N, M, dummy_ops, next);

        long long delta = next_energy - current_energy;
        if (delta < 0 || (T > 1e-9 && std::uniform_real_distribution<double>(0.0, 1.0)(rng) < std::exp(-(double)delta / T))) {
            current = next;
            current_energy = next_energy;
            if (current_energy < best_energy) {
                best_energy = current_energy;
                best_dest_choices = current;
            }
        }
        iterations++;
    }
}

// Greedy approach: for each target, pick the best single destination using heuristic
std::vector<int> generate_greedy_single_dest(const std::vector<std::vector<int>>& init_stacks, int N, int M) {
    std::vector<int> dests(N);
    State st(N, M, init_stacks);

    for (int k = 0; k < N; k++) {
        int src = st.box_pos[k].first;
        int h = st.box_pos[k].second;
        auto& stk = st.stacks[src];

        if (h == (int)stk.size() - 1) {
            dests[k] = src;
            st.carry_out(k);
            continue;
        }

        int first_above = stk[h + 1];
        int num_above = (int)stk.size() - 1 - h;

        // Pick best dest using heuristic
        double best_score = std::numeric_limits<double>::max();
        int best_dest = (src + 1) % M;

        for (int d = 0; d < M; d++) {
            if (d == src) continue;
            double score = 0.0;

            if (st.stacks[d].empty()) {
                score = 500.0;
            } else {
                score = (double)st.stacks[d].size() * 2.0;
                // Penalty for covering soon-needed boxes
                for (int bv : st.stacks[d]) {
                    if (bv > k && bv < k + 20) {
                        score += 30.0;
                    }
                }
            }

            if (score < best_score) {
                best_score = score;
                best_dest = d;
            }
        }

        dests[k] = best_dest;
        st.move(first_above, best_dest);
        st.carry_out(k);
    }

    return dests;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    GLOBAL_START_TIME = std::chrono::steady_clock::now();

    int N, M;
    std::cin >> N >> M;

    std::vector<std::vector<int>> init_stacks(M);
    for (int i = 0; i < M; i++) {
        init_stacks[i].resize(N / M);
        for (int j = 0; j < N / M; j++) {
            std::cin >> init_stacks[i][j];
            init_stacks[i][j]--; // 0-indexed
        }
    }

    // Approach 1: Multi-move with patience-sort placement
    std::vector<std::pair<int, int>> multi_ops;
    long long multi_energy = solve_multi_move(init_stacks, N, M, multi_ops, true);

    // Approach 2: Single-move with greedy + SA optimization
    std::vector<int> single_dests = generate_greedy_single_dest(init_stacks, N, M);
    std::vector<std::pair<int, int>> single_ops;
    long long single_energy = solve_single_move(init_stacks, N, M, single_ops, single_dests);

    // Run SA on single-move approach
    long long best_single_energy = single_energy;
    std::vector<int> best_single_dests = single_dests;

    double elapsed_now = std::chrono::duration<double>(std::chrono::steady_clock::now() - GLOBAL_START_TIME).count();
    double sa_budget = TIME_LIMIT_SECONDS - elapsed_now - 0.05;
    if (sa_budget > 0.1) {
        optimize_single_move_sa(init_stacks, N, M, best_single_dests, best_single_energy, sa_budget);
        if (best_single_energy < single_energy) {
            single_ops.clear();
            single_energy = solve_single_move(init_stacks, N, M, single_ops, best_single_dests);
        }
    }

    // Pick the better solution
    if (multi_energy <= single_energy && (int)multi_ops.size() <= 5000) {
        for (auto& op : multi_ops) {
            std::cout << op.first << " " << op.second << "\n";
        }
    } else if ((int)single_ops.size() <= 5000) {
        for (auto& op : single_ops) {
            std::cout << op.first << " " << op.second << "\n";
        }
    } else {
        for (auto& op : multi_ops) {
            std::cout << op.first << " " << op.second << "\n";
        }
    }

    return 0;
}
# EVOLVE-BLOCK-END

