void run_sa(const std::vector<std::vector<int>>& init_stacks, int N, int M,
            int* best_dests, long long& best_energy) {
    std::mt19937 rng(12345);

    int current_dests[200];
    for (int i = 0; i < N; i++) current_dests[i] = best_dests[i];
    long long current_energy = best_energy;

    double T_init = 40.0;
    double T_final = 0.01;

    double sa_start = std::chrono::duration<double>(std::chrono::steady_clock::now() - GLOBAL_START_TIME).count();
    double sa_end = TIME_LIMIT_SECONDS;
    double sa_duration = sa_end - sa_start;
    if (sa_duration < 0.05) return;

    SimState base_state, work_state;
    base_state.init(N, M, init_stacks);

    int next_dests[200];

    while (true) {
        double now = std::chrono::duration<double>(std::chrono::steady_clock::now() - GLOBAL_START_TIME).count();
        if (now >= sa_end) break;
        double progress = (now - sa_start) / sa_duration;
        if (progress > 1.0) progress = 1.0;
        double T = T_init * std::pow(T_final / T_init, progress);

        for (int i = 0; i < N; i++) next_dests[i] = current_dests[i];

        int op = rng() % 100;
        if (op < 45) {
            int idx = rng() % N;
            next_dests[idx] = rng() % M;
        } else if (op < 75) {
            int nc = 2 + (rng() % 3);
            for (int c = 0; c < nc; c++) {
                next_dests[rng() % N] = rng() % M;
            }
        } else if (op < 90) {
            int start = rng() % N;
            int len = 2 + (rng() % 8);
            for (int i = 0; i < len && start + i < N; i++) {
                next_dests[start + i] = rng() % M;
            }
        } else {
            int i1 = rng() % N;
            int i2 = rng() % N;
            std::swap(next_dests[i1], next_dests[i2]);
        }

        work_state.copy_from(base_state);
        long long next_energy = work_state.evaluate_plan(next_dests);

        long long delta = next_energy - current_energy;
        if (delta <= 0) {
            for (int i = 0; i < N; i++) current_dests[i] = next_dests[i];
            current_energy = next_energy;
            if (current_energy < best_energy) {
                best_energy = current_energy;
                for (int i = 0; i < N; i++) best_dests[i] = current_dests[i];
            }
        } else if (T > 1e-9 && std::uniform_real_distribution<double>(0.0, 1.0)(rng) < std::exp(-(double)delta / T)) {
            for (int i = 0; i < N; i++) current_dests[i] = next_dests[i];
            current_energy = next_energy;
        }
    }
}

long long reconstruct_single(const std::vector<std::vector<int>>& init_stacks, int N, int M,
                             const int* dests, std::vector<std::pair<int, int>>& out_ops) {
    State st(N, M, init_stacks);
    for (int k = 0; k < N; k++) {
        int src = st.box_pos[k].first;
        int h = st.box_pos[k].second;
        if (h < (int)st.stacks[src].size() - 1) {
            int first_above = st.stacks[src][h + 1];
            int dest = dests[k];
            if (dest == src) dest = (src + 1) % M;
            st.move(first_above, dest);
        }
        st.carry_out(k);
    }
    out_ops = std::move(st.ops);
    return st.energy;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    GLOBAL_START_TIME = std::chrono::steady_clock::now();

    int N, M;
    std::cin >> N >> M;

    std::vector<std::vector<int>> init_stacks(M);
    for (int i = 0; i < M; i++) {
        init_stacks[i].resize(N / M);
        for (int j = 0; j < N / M; j++) {
            std::cin >> init_stacks[i][j];
            init_stacks[i][j]--;
        }
    }

    // Approach 1: Multi-move with patience-sort
    std::vector<std::pair<int, int>> multi_ops;
    long long multi_energy = solve_multi_move(init_stacks, N, M, multi_ops);

    // Approach 2: Greedy + SA
    int best_dests[200];
    get_greedy_dests(init_stacks, N, M, best_dests);

    SimState eval_state;
    eval_state.init(N, M, init_stacks);
    long long best_sa_energy = eval_state.evaluate_plan(best_dests);

    run_sa(init_stacks, N, M, best_dests, best_sa_energy);

    // Pick better
    if (multi_energy <= best_sa_energy && (int)multi_ops.size() <= 5000) {
        for (auto& op : multi_ops) {
            std::cout << op.first << " " << op.second << "\n";
        }
    } else {
        std::vector<std::pair<int, int>> sa_ops;
        reconstruct_single(init_stacks, N, M, best_dests, sa_ops);
        if ((int)sa_ops.size() <= 5000) {
            for (auto& op : sa_ops) {
                std::cout << op.first << " " << op.second << "\n";
            }
        } else {
            for (auto& op : multi_ops) {
                std::cout << op.first << " " << op.second << "\n";
            }
        }
    }

    return 0;
}
